document.addEventListener("DOMContentLoaded",(()=>{fetch("../assets/data/trip.json").then((n=>n.json())).then((n=>{const e=document.querySelector("main"),t=document.createElement("div");t.classList.add("header"),t.innerHTML=`<h1>${n.title}</h1>`,e.appendChild(t),n.days.forEach((n=>{const t=document.createElement("div");t.classList.add("day"),t.innerHTML=`<h2>${n.day}</h2>`;const i=document.createElement("div");i.classList.add("day-content"),n.checkpoints.forEach((n=>{const e=document.createElement("div");e.classList.add("day-content-checkpoint"),n.class&&e.classList.add(n.class),e.innerHTML=`\n            <div class="day-content-checkpoint-timeline">\n              <div class="day-content-checkpoint-timeline-time">${n.time}</div>\n              <div class="day-content-checkpoint-timeline-line"></div>\n            </div>\n            <div class="day-content-checkpoint-info">\n              <div class="day-content-checkpoint-info-title">\n                ${n.icon?`<i class="fa-solid ${n.icon}"></i>`:""} ${n.title}\n              </div>\n              <div class="day-content-checkpoint-info-description">${n.description}</div>\n            </div>\n          `,i.appendChild(e)})),t.appendChild(i),e.appendChild(t)}))})).catch((n=>console.error("Error loading itinerary:",n)))}));